const ctx = $('🔗 Объединение данных').first().json;

const videoPrompt = ctx.prompt_text || 'Create a professional vertical video (9:16) showcasing: ' + ctx.title + '. ' + (ctx.visual_description || ctx.concept || '');

const body = JSON.stringify({
  model: 'video-01',
  prompt: videoPrompt,
  first_frame_image: ctx.product_image_url || undefined
});

return [{ json: { body, session_id: ctx.session_id } }];

const response = $input.first().json;
const taskId = response.task_id;
if (!taskId) throw new Error('Video provider did not return task_id: ' + JSON.stringify(response).substring(0, 500));

return [{ json: {
  task_id: taskId,
  session_id: $('🔗 Объединение данных').first().json.session_id,
  poll_count: 0
}}];

const prev = $input.first().json;
const pollCount = (prev.poll_count || 0) + 1;
if (pollCount > 40) throw new Error('Video generation timeout: 40 polls (10 min)');
return [{ json: { task_id: prev.task_id || $('🔑 Извлечь task_id').first().json.task_id, session_id: prev.session_id || $('🔑 Извлечь task_id').first().json.session_id, poll_count: pollCount } }];

const response = $input.first().json;
const fileId = response.file_id || '';
const videoUrl = response.video_url || '';
const rawVideoUrl = videoUrl || fileId;
if (!rawVideoUrl) throw new Error('Video provider did not return video URL or file_id');
const sessionId = $('🔑 Извлечь task_id').first().json.session_id;
return [{ json: {
  session_id: sessionId,
  raw_video_url: rawVideoUrl,
  file_id: fileId,
  ...$('🔗 Объединение данных').first().json
}}];

