parameters.jsCode:
const ctx = $('🔗 Объединение данных').first().json;
const sessionId = ctx.session_id;
const voicePath = '/home/node/output/voice_' + sessionId + '.mp3';
const outputPath = '/home/node/output/final_' + sessionId + '.mp4';
const workDir = '/tmp/montage_' + sessionId;

// Определяем URL для скачивания видео
const retrieveResp = $('📥 Получить файл видео').first().json;
const gotUrlData = $('🎬 URL видео').first().json;
let rawVideoUrl = '';
if (retrieveResp && retrieveResp.file && retrieveResp.file.download_url) {
  rawVideoUrl = retrieveResp.file.download_url;
} else if (gotUrlData.raw_video_url && gotUrlData.raw_video_url.startsWith('http')) {
  rawVideoUrl = gotUrlData.raw_video_url;
} else {
  throw new Error('Нет URL для скачивания видео. file_id=' + (gotUrlData.file_id || 'N/A'));
}

const subtitlesEnabled = ctx.subtitles_enabled || false;
const musicKey = ctx.music_file_key || '';
const musicVolume = parseFloat(ctx.music_volume) || 0.3;

// Генерация SRT из timing_marks
let srtContent = '';
if (subtitlesEnabled) {
  const marks = Array.isArray(ctx.timing_marks) ? ctx.timing_marks : [];
  const fmtTime = (s) => {
    const h = String(Math.floor(s / 3600)).padStart(2, '0');
    const m = String(Math.floor((s % 3600) / 60)).padStart(2, '0');
    const sec = String(Math.floor(s % 60)).padStart(2, '0');
    const ms = String(Math.round((s % 1) * 1000)).padStart(3, '0');
    return h + ':' + m + ':' + sec + ',' + ms;
  };
  for (let i = 0; i < marks.length; i++) {
    const startSec = parseFloat(marks[i].time) || 0;
    const endSec = marks[i + 1] ? parseFloat(marks[i + 1].time) : startSec + 4;
    srtContent += (i + 1) + '\n' + fmtTime(startSec) + ' --> ' + fmtTime(endSec) + '\n' + (marks[i].text || '') + '\n\n';
  }
}

const hasSubs = subtitlesEnabled && srtContent.length > 0;
const hasMusic = !!musicKey;

// Формируем shell-скрипт
const lines = ['set -e', 'mkdir -p ' + workDir];

// Скачать видео
lines.push('wget -q --timeout=180 -O ' + workDir + '/raw.mp4 "' + rawVideoUrl.replace(/"/g, '\\"') + '"');

// Скачать музыку
if (hasMusic) {
  lines.push('wget -q --timeout=60 -O ' + workDir + '/music.mp3 "http://minio:9000/content-factory/' + musicKey + '"');
}

// Записать SRT через base64 (безопасно для спец.символов)
if (hasSubs) {
  const srtBase64 = Buffer.from(srtContent, 'utf8').toString('base64');
  lines.push('echo "' + srtBase64 + '" | base64 -d > ' + workDir + '/subs.srt');
}

// FFmpeg команда
let ffCmd = 'ffmpeg -y -i ' + workDir + '/raw.mp4 -i ' + voicePath;
if (hasMusic) ffCmd += ' -i ' + workDir + '/music.mp3';

// Аудио фильтр
let audioFilter;
if (hasMusic) {
  audioFilter = '[1:a]volume=1.0[voice];[2:a]volume=' + musicVolume + '[music];[voice][music]amix=inputs=2:duration=first:dropout_transition=2[aout]';
} else {
  audioFilter = '[1:a]anull[aout]';
}
ffCmd += ' -filter_complex \'' + audioFilter + '\'';

// Видео фильтр для субтитров
if (hasSubs) {
  const font = ctx.subtitle_font || 'DejaVu Sans';
  const size = ctx.subtitle_size || 42;
  const color = ctx.subtitle_color || 'white';
  const outline = ctx.subtitle_outline || 2;
  const assColor = color === 'yellow' ? '&H0000FFFF' : color === 'red' ? '&H000000FF' : '&H00FFFFFF';
  const vf = 'subtitles=' + workDir + '/subs.srt:force_style=\'FontName=' + font + ',FontSize=' + size + ',PrimaryColour=' + assColor + ',OutlineColour=&H00000000&,Outline=' + outline + ',Alignment=2,MarginV=40\'';
  ffCmd += ' -vf "' + vf + '"';
}

ffCmd += ' -map 0:v -map \'[aout]\' -c:v libx264 -preset fast -crf 23 -c:a aac -b:a 192k -shortest ' + outputPath;

lines.push(ffCmd);
lines.push('rm -rf ' + workDir);
lines.push('echo MONTAGE_DONE');

return [{ json: { command: lines.join('\n'), session_id: sessionId, output_path: outputPath } }];
